import py4godot.classes.Camera3D as py4godot_camera3d 
from py4godot.wrappers.wrappers import CPPXRCamera3DWrapper


class XRCamera3D(py4godot_camera3d.Camera3D):
  r'''
		A camera node which automatically positions itself based on XR tracking data.
		In contrast to `XRController3D`, the render thread has access to more up-to-date tracking data, and the location of the `XRCamera3D` node can lag a few milliseconds behind what is used for rendering.
		**Note:** If `Viewport.use_xr` is `true`, most of the camera properties are overridden by the active `XRInterface`. The only properties that can be trusted are the near and far planes.
	'''

  @staticmethod
  def constructor():
    class_ = XRCamera3D.construct_without_init()
    class_._ptr = constructor(1070,0, ())
    return class_
  @staticmethod
  def new():
    class_ = XRCamera3D.construct_without_init()
    class_._ptr = constructor(1070,0, ())
    return class_
  def __init__(self):
    self._ptr =  CPPXRCamera3DWrapper()
    self.casted_from = None
    if c_utils.shouldCreateObject:
      self._ptr = constructor(1070,0, ())


  def generate_wrapper(self):
    return CPPXRCamera3DWrapper()
  def init_signals(self):
    super().init_signals()

  @staticmethod
  def construct_without_init():
    cls = XRCamera3D.__new__(XRCamera3D)
    cls.shouldBeDeleted = True
    cls.casted_from = None
    cls.constructed_from_python = False
    cls.init_signals()
    return cls
  @staticmethod
  def get_type():
    return 'XRCamera3D'

  def __del__(self):
    pass
  @staticmethod
  def cast(other:'Object'):
    assert other != None # Object to be casted must not be None
    cls = XRCamera3D.construct_without_init()
    cls._ptr = CPPXRCamera3DWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls
  @staticmethod
  def cast_without_reference(other: 'Object'):
    assert other != None # Object to be casted must not be None
    cls = XRCamera3D.construct_without_init()
    cls._ptr = CPPXRCamera3DWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls


register_cast_function('XRCamera3D', XRCamera3D.cast)
register_class('XRCamera3D', XRCamera3D)
